import { useState, createContext } from 'react'
import axios from 'axios'


const BookContext = createContext()

const BookProvider = ({children}) => {

    const [search, setSearch] = useState({
        query: ''
    })

    const [loading, setLoading] = useState(false)
    const [bookData, setBookData] = useState([])

    const [currentPage, setCurrentPage] = useState(1);
    const [totalPages, setTotalPages] = useState(0);

    const setBookDataWithPagination = (data) => {
        setTotalPages(Math.ceil(data.totalItems / 40));
        setBookData((prevData) => [...prevData, ...data.items]);
  };


    const getBookList = async () => {
        setLoading(true);

        try {
        const startIndex = (currentPage - 1) * 40;
        const url = `https://www.googleapis.com/books/v1/volumes?q=${search.query}&key=${process.env.REACT_APP_GOOGLE_BOOKS_API_KEY}&startIndex=${startIndex}&maxResults=40&printType=books`;
        const { data: res } = await axios(url);

        if (res && res.items) {
            setBookDataWithPagination(res);
        } else {
            setBookData([]);
        }
        } catch (error) {
        console.error(error);
        } finally {
        setLoading(false);
        }
    };

    const clearBookList = () => {
        setBookData([]);
    };
    

    const [userBooks, setUserBooks] = useState([])

    const [userSearched, setUserSearched] = useState([])



    return (
        <BookContext.Provider value={{ getBookList, clearBookList, bookData, search, setSearch, loading, setLoading, userBooks, setUserBooks, userSearched, setUserSearched, currentPage, totalPages, setCurrentPage, setBookDataWithPagination }}>
            {children}
        </BookContext.Provider>
    )
}

export { BookProvider }

export default BookContext
